function byteLength(t){return t.length}function toString(t){const e=t.byteLength;let n="";for(let r=0;r<e;r++)n+=String.fromCharCode(127&t[r]);return n}function write(t,e){const n=t.byteLength;for(let r=0;r<n;r++)t[r]=e.charCodeAt(r);return n}module.exports={byteLength:byteLength,toString:toString,write:write};